      key: 'Authorization',
      value: `Basic ${this.toBase64(`${username}:${password}`)}`,
      explode: false,
      style: SerializationStyle.SIMPLE,
      encode: true,
      isLimit: false,
      isOffset: false,
      isCursor: false,
    });
    return this;
  }

