    const reader = response.body.getReader();
    const lineDecoder = new LineDecoder();

    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        break;
      }

      for (const line of lineDecoder.splitLines(value)) {
        yield {
          metadata,
          raw: this.toArrayBuffer(line),
